/**
 * Send native desktop notification (cross-platform)
 * Windows: Uses PowerShell toast notifications
 * macOS: Uses osascript
 * Linux: Uses libnotify (notify-send)
 */
export async function sendDesktop(
  title: string,
  message: string,
  options: {
    sound?: string;       // Sound name (platform-specific)
    subtitle?: string;
  } = {}
): Promise<boolean> {
  try {
    const { PLATFORM } = await import('./platform-paths');

    if (PLATFORM === 'win32') {
      // Windows: Use PowerShell to show a toast notification
      const escapedMessage = message.replace(/"/g, '\\"');
      const escapedTitle = title.replace(/"/g, '\\"');
      const script = `
        [Windows.UI.Notifications.ToastNotificationManager, Windows.UI.Notifications, ContentType = WindowsRuntime] | Out-Null
        [Windows.UI.Notifications.ToastNotification, Windows.UI.Notifications, ContentType = WindowsRuntime] | Out-Null
        [Windows.Data.Xml.Dom.XmlDocument, Windows.Data.Xml.Dom.XmlDocument, ContentType = WindowsRuntime] | Out-Null

        $template = @"
        <toast><visual><binding template='ToastGeneric'><text>${escapedTitle}</text><text>${escapedMessage}</text></binding></visual></toast>
        "@

        $xml = New-Object Windows.Data.Xml.Dom.XmlDocument
        $xml.LoadXml($template)
        $toast = New-Object Windows.UI.Notifications.ToastNotification $xml
        $notifier = [Windows.UI.Notifications.ToastNotificationManager]::CreateToastNotifier('PAI')
        $notifier.Show($toast)
      `;

      const proc = Bun.spawn(['powershell', '-NoProfile', '-Command', script]);
      await proc.exited;
      return proc.exitCode === 0;
    } else if (PLATFORM === 'darwin') {
      // macOS: Use osascript
      const soundPart = options.sound ? ` sound name "${options.sound}"` : '';
      const subtitlePart = options.subtitle ? ` subtitle "${options.subtitle}"` : '';

      const script = `display notification "${message}" with title "${title}"${subtitlePart}${soundPart}`;

      const proc = Bun.spawn(['osascript', '-e', script]);
      await proc.exited;

      return proc.exitCode === 0;
    } else {
      // Linux: Use notify-send (part of libnotify)
      const proc = Bun.spawn(['notify-send', title, message]);
      await proc.exited;
      return proc.exitCode === 0;
    }
  } catch (error) {
    console.error('Desktop notification failed:', error);
    return false;

