/**
 * Core emit function - appends event to TRACE.jsonl
 * Fail-open design: never throws, never blocks
 *
 * WINDOWS ENHANCEMENT:
 * - Checks path length before writing (Windows MAX_PATH = 260 chars)
 * - Provides helpful error message if path too long
 */
export function emit(event: Omit<TraceEvent, 'ts'>): void {
  const tracePath = getTracePath();
  if (!tracePath) {
    if (DEBUG) console.error('[TraceEmitter] No work dir, skipping emit');
    return;
  }

  // Windows-specific: Check path length
  if (IS_WINDOWS && tracePath.length > 250) {
    console.error('[TraceEmitter] WARNING: Trace path approaches Windows MAX_PATH limit:');
    console.error(`[TraceEmitter] Path length: ${tracePath.length} characters`);
    console.error(`[TraceEmitter] Limit: 260 characters`);
    console.error(`[TraceEmitter] Path: ${tracePath}`);
    console.error('[TraceEmitter] Consider enabling long path support or using shorter project paths');
  }

  const fullEvent: TraceEvent = {
    ts: new Date().toISOString(),
    ...event
  };

  try {
    // Ensure directory exists
    const dir = dirname(tracePath);
    if (!existsSync(dir)) {
      mkdirSync(dir, { recursive: true });
    }

    // Check for rotation
    rotateIfNeeded(tracePath);

    // Atomic append
    appendFileSync(tracePath, JSON.stringify(fullEvent) + '\n');

    if (DEBUG) console.error('[TraceEmitter] Emitted:', event.type, event.hook || '');
  } catch (e) {
    // Fail open - log but don't crash
    if (DEBUG) {
      console.error('[TraceEmitter] Write failed:', e);

      // Provide Windows-specific troubleshooting
      if (IS_WINDOWS && e.code === 'ENOENT') {
        console.error('[TraceEmitter] Windows troubleshooting:');
        console.error('[TraceEmitter] 1. Check directory exists and is accessible');
        console.error('[TraceEmitter] 2. Check path length (< 260 chars)');
        console.error('[TraceEmitter] 3. Ensure proper permissions');
      }
    }
  }
}

